// 학원별 데이터 격리 헬퍼
// ══════════════════════════════════════════
function getAcademySlug() {
  try {
    const sub = JSON.parse(localStorage.getItem('mathiq:activeSub') || 'null');
    return sub?.slug || 'default';
  } catch { return 'default'; }
}
// slug를 포함한 격리된 localStorage 키 반환
function slugKey(base) {
  return `${base}:${getAcademySlug()}`;
}
// 학생 보고서 키 (슬러그 기반 격리)
function reportKey(studentName) {
  const slug = getAcademySlug();
  return slug === 'default' ? `report:${studentName}` : `report:${slug}:${studentName}`;
}
// 알림장 키 (슬러그 기반 격리)
function noticeKey() { return slugKey('paran:notices'); }
// 상담메모 키 (슬러그 기반 격리)
function consultKey() { return slugKey('paran:consults'); }
// 오답은행 키 (슬러그 기반 격리)
function wrongProblemsKey() { return slugKey('paran:wrongProblems'); }
// 학생 오답노트 키 (슬러그 기반 격리)
function wrongBankKey(studentName) { return slugKey(`paran:wrongbank:${studentName}`); }
// 학부모 메시지 키 (슬러그 기반 격리)
function msgKey(studentName) { return slugKey(`paran:messages:${studentName}`); }

