// ── localStorage 오버라이드 지원 ──
const PLAN_FEATURES_KEY = 'mathiq:planFeatures';
function loadPlanFeatures() {
  try {
    const saved = localStorage.getItem(PLAN_FEATURES_KEY);
    return saved ? JSON.parse(saved) : { ...PLAN_FEATURES_DEFAULT };
  } catch { return { ...PLAN_FEATURES_DEFAULT }; }
}
function savePlanFeatures(data) {
  localStorage.setItem(PLAN_FEATURES_KEY, JSON.stringify(data));
  window.dispatchEvent(new Event('planFeaturesUpdated'));
}

// 실제 사용되는 PLAN_FEATURES (런타임에 localStorage 우선)
let PLAN_FEATURES = loadPlanFeatures();
window.addEventListener('planFeaturesUpdated', () => { PLAN_FEATURES = loadPlanFeatures(); });
// 플랜별 디자인 기능 레벨
// 스타터/베이직: 테마 선택 불가 (관리 시스템만)
// 스탠다드+: 테마 50종 선택 가능
// 스탠다드+: AI 디자인 생성 가능 (API 연동 시)
// 무료 체험(trial): 신청한 플랜 기준으로 적용
const DESIGN_PLAN_LEVEL = (plan) => {
  if (['스탠다드','프리미엄','엔터프라이즈'].includes(plan)) return 'full';   // 50종+AI
  return 'none';                                                                // 스타터·베이직: 불가
};

