function loadLandingText() {
  try {
    const saved = localStorage.getItem(MATHIQ_LANDING_KEY);
    return saved ? { ...DEFAULT_LANDING_TEXT, ...JSON.parse(saved) } : { ...DEFAULT_LANDING_TEXT };
  } catch { return { ...DEFAULT_LANDING_TEXT }; }
}
function saveLandingText(data) {
  localStorage.setItem(MATHIQ_LANDING_KEY, JSON.stringify(data));
}

// ========== MathIQ Pro 랜딩 텍스트 편집기 ==========
function MathIQLandingEditor({ onClose }) {
  const [text, setText] = useState(() => loadLandingText());
  const [saved, setSaved] = useState(false);

  const Field = ({ label, k, multiline }) => (
    <div style={{ marginBottom: '12px' }}>
      <label style={{ display: 'block', fontSize: '11px', fontWeight: 700, color: '#6b7280', marginBottom: '4px', textTransform: 'uppercase', letterSpacing: '.5px' }}>{label}</label>
      {multiline ? (
        <textarea value={text[k]} onChange={e => setText(t => ({ ...t, [k]: e.target.value }))}
          rows={3} style={{ width: '100%', padding: '8px 12px', border: '1.5px solid #e5e7eb', borderRadius: '8px', fontSize: '13px', fontFamily: 'inherit', resize: 'vertical', boxSizing: 'border-box', outline: 'none' }} />
      ) : (
        <input value={text[k]} onChange={e => setText(t => ({ ...t, [k]: e.target.value }))}
          style={{ width: '100%', padding: '8px 12px', border: '1.5px solid #e5e7eb', borderRadius: '8px', fontSize: '13px', fontFamily: 'inherit', boxSizing: 'border-box', outline: 'none' }} />
      )}
    </div>
  );

  const Sec = ({ title, children }) => (
    <div style={{ background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: '12px', padding: '18px', marginBottom: '14px' }}>
      <div style={{ fontSize: '13px', fontWeight: 800, color: '#1e40af', marginBottom: '14px', paddingBottom: '8px', borderBottom: '2px solid #dbeafe' }}>{title}</div>
      {children}
    </div>
  );

  const handleSave = () => {
    saveLandingText(text);
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
    window.dispatchEvent(new Event('mathiqLandingUpdated'));
  };

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.65)', zIndex: 9999, overflowY: 'auto', padding: '20px', display: 'flex', justifyContent: 'center' }}>
      <div style={{ background: '#fff', borderRadius: '20px', padding: '32px', maxWidth: '680px', width: '100%', height: 'fit-content', fontFamily: 'inherit' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h2 style={{ fontSize: '18px', fontWeight: 900, color: '#111827' }}>✏️ MathIQ Pro 랜딩 페이지 편집</h2>
            <p style={{ fontSize: '12px', color: '#6b7280', marginTop: '2px' }}>저장 즉시 반영됩니다</p>
          </div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => { if(window.confirm('기본값으로 초기화할까요?')) { setText({...DEFAULT_LANDING_TEXT}); saveLandingText(DEFAULT_LANDING_TEXT); window.dispatchEvent(new Event('mathiqLandingUpdated')); }}}
              style={{ padding: '8px 14px', background: '#f3f4f6', border: '1px solid #e5e7eb', borderRadius: '8px', fontSize: '12px', fontWeight: 600, color: '#6b7280', cursor: 'pointer', fontFamily: 'inherit' }}>초기화</button>
            <button onClick={handleSave}
              style={{ padding: '8px 18px', background: saved ? '#10b981' : '#2563eb', color: '#fff', border: 'none', borderRadius: '8px', fontSize: '13px', fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit', transition: 'background .2s' }}>
              {saved ? '✅ 저장됨' : '💾 저장'}
            </button>
            <button onClick={onClose} style={{ padding: '8px 12px', background: '#f3f4f6', border: '1px solid #e5e7eb', borderRadius: '8px', fontSize: '16px', cursor: 'pointer' }}>✕</button>
          </div>
        </div>

        <Sec title="🚀 히어로 섹션">
          <Field label="태그라인" k="hero_tag" />
          <Field label="제목 1줄" k="hero_title1" />
          <Field label="제목 2줄 (강조색)" k="hero_title2" />
          <Field label="설명 (줄바꿈: \\n 입력)" k="hero_desc" multiline />
          <Field label="CTA 버튼" k="hero_btn" />
          <Field label="버튼 아래 주석" k="hero_note" />
        </Sec>

        <Sec title="⚡ 기능 섹션">
          <Field label="태그" k="feat_tag" />
          <Field label="제목 1줄" k="feat_title1" />
          <Field label="제목 2줄" k="feat_title2" />
        </Sec>

        <Sec title="💳 요금제 섹션">
          <Field label="태그" k="plan_tag" />
          <Field label="제목" k="plan_title" />
        </Sec>

        <Sec title="⭐ 후기 섹션">
          <Field label="태그" k="review_tag" />
          <Field label="제목 1줄" k="review_title1" />
          <Field label="제목 2줄" k="review_title2" />
          {[1,2,3].map(i => (
            <div key={i} style={{ background: '#fff', border: '1px solid #e5e7eb', borderRadius: '10px', padding: '14px', marginTop: '12px' }}>
              <div style={{ fontSize: '12px', fontWeight: 700, color: '#374151', marginBottom: '10px' }}>후기 {i}</div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                <Field label="지역" k={`review${i}_loc`} />
                <Field label="이름" k={`review${i}_name`} />
              </div>
              <Field label="내용" k={`review${i}_text`} multiline />
            </div>
          ))}
        </Sec>

        <Sec title="❓ FAQ">
          <Field label="태그" k="faq_tag" />
          <Field label="제목" k="faq_title" />
          {[1,2,3,4,5].map(i => (
            <div key={i} style={{ background: '#fff', border: '1px solid #e5e7eb', borderRadius: '10px', padding: '14px', marginTop: '10px' }}>
              <div style={{ fontSize: '12px', fontWeight: 700, color: '#374151', marginBottom: '8px' }}>FAQ {i}</div>
              <Field label="질문" k={`faq${i}_q`} />
              <Field label="답변" k={`faq${i}_a`} multiline />
            </div>
          ))}
        </Sec>

        <Sec title="🎯 하단 CTA">
          <Field label="제목" k="cta_title" />
          <Field label="설명" k="cta_desc" />
          <Field label="버튼" k="cta_btn" />
        </Sec>

        <div style={{ textAlign: 'center', paddingTop: '8px' }}>
          <button onClick={handleSave}
            style={{ padding: '14px 48px', background: saved ? '#10b981' : '#2563eb', color: '#fff', border: 'none', borderRadius: '12px', fontSize: '15px', fontWeight: 800, cursor: 'pointer', fontFamily: 'inherit', boxShadow: '0 4px 16px rgba(37,99,235,.3)' }}>
            {saved ? '✅ 저장 완료!' : '💾 변경사항 저장'}
          </button>
        </div>
      </div>
    </div>
  );
}

