                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                      member.role === '경리' ? 'bg-amber-100 text-amber-700' :
                      'bg-blue-100 text-blue-700'
                    }`}>
                      {member.role === '경리' ? '💰' : '📋'} {member.role === '경리' ? '경리/상담' : member.role}
                    </span>
