  // 📝 종이 검사 결과 분석 (직접 입력용)
  const analyzeManualInput = () => {
    const { personality, aptitude } = manualInputData;
    
    // MBTI 분석
    let mbti = '';
    const categories = ['EI', 'SN', 'TF', 'JP'];
    categories.forEach(cat => {
      const questions = personalityQuestions.filter(q => q.category === cat);
      let aCount = 0, bCount = 0;
      questions.forEach(q => {
        if (personality[q.id] === 'A') aCount++;
        else if (personality[q.id] === 'B') bCount++;
      });
      if (cat === 'EI') mbti += aCount >= bCount ? 'E' : 'I';
      else if (cat === 'SN') mbti += aCount >= bCount ? 'S' : 'N';
      else if (cat === 'TF') mbti += aCount >= bCount ? 'T' : 'F';
      else if (cat === 'JP') mbti += aCount >= bCount ? 'J' : 'P';
    });
    
    // RIASEC 분석
    const riasecScores = { R: 0, I: 0, A: 0, S: 0, E: 0, C: 0 };
    aptitudeQuestions.forEach(q => {
      const answer = aptitude[q.id] || 3;
      if (answer === 5) riasecScores[q.category] += 3;
      else if (answer === 4) riasecScores[q.category] += 2;
      else if (answer === 3) riasecScores[q.category] += 1;
      else if (answer === 2) riasecScores[q.category] += 0;
      else if (answer === 1) riasecScores[q.category] -= 1;
    });
    
    const sortedRiasec = Object.entries(riasecScores).sort((a, b) => b[1] - a[1]);
    const topTwo = sortedRiasec.slice(0, 2).map(x => x[0]).join('');
    const topThree = sortedRiasec.slice(0, 3).map(x => x[0]).join('');
    
    const primaryCareers = careerDatabase[topTwo] || [];
    const secondaryCareers = careerDatabase[sortedRiasec[0][0] + sortedRiasec[2][0]] || [];
    const recommendedCareers = [...new Set([...primaryCareers, ...secondaryCareers])].slice(0, 10);
    
    const mbtiDescriptions = {
      'ISTJ': { name: '청렴결백형', desc: '책임감이 강하고 신뢰할 수 있는 성격입니다.' },
      'ISFJ': { name: '임금뒤편의 권력형', desc: '따뜻하고 헌신적입니다.' },
      'INFJ': { name: '예언자형', desc: '직관력이 뛰어나고 이상주의적입니다.' },
      'INTJ': { name: '과학자형', desc: '분석적이고 전략적입니다.' },
      'ISTP': { name: '백과사전형', desc: '논리적이고 실용적입니다.' },
      'ISFP': { name: '성인군자형', desc: '조용하고 친절합니다.' },
      'INFP': { name: '잔다르크형', desc: '이상주의적이고 창의적입니다.' },
      'INTP': { name: '아이디어뱅크형', desc: '논리적이고 분석적입니다.' },
      'ESTP': { name: '수완좋은 활동가형', desc: '활동적이고 현실적입니다.' },
      'ESFP': { name: '사교적인 유형', desc: '사교적이고 즐겁습니다.' },
      'ENFP': { name: '스파크형', desc: '열정적이고 창의적입니다.' },
      'ENTP': { name: '발명가형', desc: '창의적이고 도전적입니다.' },
      'ESTJ': { name: '사업가형', desc: '체계적이고 리더십이 있습니다.' },
      'ESFJ': { name: '친선도모형', desc: '따뜻하고 협조적입니다.' },
      'ENFJ': { name: '언변능숙형', desc: '카리스마가 있습니다.' },
      'ENTJ': { name: '지도자형', desc: '단호하고 목표지향적입니다.' }
    };
    
    const riasecDescriptions = {
      'R': { name: '현실형', icon: '🔧', desc: '손으로 직접 만들고 도구를 다루는 것을 좋아합니다.', color: '#dc2626' },
      'I': { name: '탐구형', icon: '🔬', desc: '과학적 탐구와 분석을 좋아합니다.', color: '#2563eb' },
      'A': { name: '예술형', icon: '🎨', desc: '창의적인 활동과 자기표현을 좋아합니다.', color: '#7c3aed' },
      'S': { name: '사회형', icon: '🤝', desc: '다른 사람을 돕고 가르치는 것을 좋아합니다.', color: '#16a34a' },
      'E': { name: '진취형', icon: '👔', desc: '리더십을 발휘하고 사업을 좋아합니다.', color: '#ea580c' },
      'C': { name: '관습형', icon: '📋', desc: '체계적이고 정확하게 일하는 것을 좋아합니다.', color: '#0891b2' }
    };
    
    const result = {
      completed: true,
      completedAt: new Date().toISOString(),
      mbti,
      mbtiInfo: mbtiDescriptions[mbti] || { name: mbti, desc: '성격 분석 결과입니다.' },
      riasecScores,
      riasecTop: sortedRiasec.slice(0, 3).map(([code, score]) => ({
        code,
        score,
        ...riasecDescriptions[code]
      })),
      topTwoCode: topTwo,
      topThreeCode: topThree,
      recommendedCareers,
      answers: { personality, aptitude },
      inputMethod: 'manual' // 직접 입력 표시
    };
    
    setReportData(prev => ({
      ...prev,
      personalityTest: result
    }));
    
    setShowManualInput(false);
    alert('✅ 검사 결과가 저장되었습니다!');
  };

  const [expandedSections, setExpandedSections] = useState({
    student: true, sessions: true, growth: true, goal: true,
    attendance: true, weakUnits: true, mistakeNotes: true,
    testSchedule: true, comments: true, prep: true, repeatAlerts: true
  });

  const [savedStudents, setSavedStudents] = useState([]);
  const [showStudentList, setShowStudentList] = useState(false);
  const [saveStatus, setSaveStatus] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  
  // 데이터 교환 모달 상태
  const [showDataExchangeModal, setShowDataExchangeModal] = useState(false);
  const [exchangeMode, setExchangeMode] = useState('export'); // 'export' | 'import'
  const [importFile, setImportFile] = useState(null);
  const [importPreview, setImportPreview] = useState(null);
  const [importStatus, setImportStatus] = useState('');
  const [importNewTeacher, setImportNewTeacher] = useState(''); // 이관 시 새 담당 선생님
  
  // 다운로드 모달 상태
  const [showDownloadModal, setShowDownloadModal] = useState(false);
  const [downloadSettings, setDownloadSettings] = useState({
    reportNumber: 1,
    filterType: 'all',
    startSession: 1,
    endSession: 4,
    startDate: '',
    endDate: ''
  });

  // 채점 기능 상태
  const [showGradingModal, setShowGradingModal] = useState(false);
  const [gradingStep, setGradingStep] = useState(1); // 1: 시험 설정, 2: 답안 입력, 3: 결과
  const [examTemplate, setExamTemplate] = useState({
    examName: '',
    examDate: new Date().toISOString().split('T')[0],
    examType: '일일테스트',
    totalQuestions: 10,
    questions: [] // { number, correctAnswer, points, unit, questionType }
  });
  const [studentAnswers, setStudentAnswers] = useState([]); // 학생 답안
  const [gradingResult, setGradingResult] = useState(null); // 채점 결과
  const [savedExamTemplates, setSavedExamTemplates] = useState([]); // 저장된 시험 템플릿
  const [templateSaveStatus, setTemplateSaveStatus] = useState(''); // 템플릿 저장 상태
  const [templateDeleteConfirm, setTemplateDeleteConfirm] = useState(null); // 삭제 확인할 템플릿명

  // ========== 저장된 학생 목록 불러오기 ==========
  useEffect(() => {
    loadStudentList();
  }, []);

  // students prop이 바뀌면(선생님 필터) savedStudents도 다시 필터링
  useEffect(() => {
    if (userType === 'teacher' && students.length >= 0) {
      setSavedStudents(prev => {
        const allowedNames = new Set(students.map(s => s.name));
        return prev.filter(name => allowedNames.has(name));
      });
    }
  }, [students, userType]);

  const loadStudentList = async () => {
    try {
      // slug 기반 prefix로만 조회하여 다른 학원 데이터 차단
      const slug = getAcademySlug();
      const prefix = slug === 'default' ? 'report:' : `report:${slug}:`;
      const result = await window.storage.list(prefix);
      if (result && result.keys) {
        let names = result.keys.map(key => key.replace(prefix, ''));
        // 빈 문자열 제거 (prefix 자체가 key로 잡힌 경우)
        names = names.filter(name => name.trim().length > 0);
        // 선생님은 담당 학생(students prop)에 있는 이름만 표시
        if (userType === 'teacher') {
          const allowedNames = new Set(students.map(s => s.name));
          names = names.filter(name => allowedNames.has(name));
        }
        setSavedStudents(names);
      }
    } catch (error) {
      console.log('학생 목록 로드 실패:', error);
      // localStorage fallback: 슬러그 기반 키로 스캔
      try {
        const slug = getAcademySlug();
        const prefix = slug === 'default' ? 'report:' : `report:${slug}:`;
        const names = Object.keys(localStorage)
          .filter(k => k.startsWith(prefix))
          .map(k => k.replace(prefix, ''))
          .filter(n => n.trim().length > 0);
        if (userType === 'teacher') {
          const allowedNames = new Set(students.map(s => s.name));
          setSavedStudents(names.filter(n => allowedNames.has(n)));
        } else {
          setSavedStudents(names);
        }
      } catch (e2) {
        console.log('localStorage fallback 실패:', e2);
      }
    }
  };

  const loadStudentData = async (studentName) => {
    if (!studentName || studentName.trim() === '') return false;
    // 선생님은 담당 학생만 로드 가능
    if (userType === 'teacher') {
      const allowed = students.some(s => s.name === studentName.trim());
      if (!allowed) {
        alert('담당 학생이 아닙니다. 원장님께 배정을 요청해 주세요.');
        return false;
      }
    }
    setIsLoading(true);
    try {
      const result = await window.storage.get(reportKey(studentName.trim()));
      if (result && result.value) {
        const loadedData = JSON.parse(result.value);
        
        // 학생 관리에서 추가 정보 가져오기
        const studentInfo = students.find(s => s.name === studentName.trim());
        if (studentInfo) {
          loadedData.grade = loadedData.grade || studentInfo.grade || '';
          loadedData.className = loadedData.className || studentInfo.className || '';
          loadedData.schoolName = studentInfo.schoolName || loadedData.schoolName || '';
          loadedData.schoolGrade = studentInfo.schoolGrade || loadedData.schoolGrade || '';
          loadedData.schoolSemester = studentInfo.schoolSemester || loadedData.schoolSemester || '';
          loadedData.levelStage = studentInfo.levelStage || loadedData.levelStage || '';
          loadedData.schoolScores = studentInfo.schoolScores || loadedData.schoolScores || [];
          loadedData.shortTermGoal = studentInfo.shortTermGoal || loadedData.shortTermGoal || '';
          loadedData.longTermGoal = studentInfo.longTermGoal || loadedData.longTermGoal || '';
        }
        
        setReportData(prev => ({ ...loadedData, studentName: studentName }));
        setSaveStatus('saved');
        setIsLoading(false);
        return true;
      } else {
        // 저장된 보고서가 없는 경우, 학생 관리 데이터로 초기화
        const studentInfo = students.find(s => s.name === studentName.trim());
        if (studentInfo) {
          setReportData(prev => ({
            ...prev,
            studentName: studentName,
            grade: studentInfo.grade || '',
            className: studentInfo.className || '',
            schoolName: studentInfo.schoolName || '',
            schoolGrade: studentInfo.schoolGrade || '',
            schoolSemester: studentInfo.schoolSemester || '',
            levelStage: studentInfo.levelStage || '',
            schoolScores: studentInfo.schoolScores || [],
            shortTermGoal: studentInfo.shortTermGoal || '',
            longTermGoal: studentInfo.longTermGoal || ''
          }));
        }
      }
    } catch (error) {
      console.log('데이터 로드 실패:', error);
    }
    setIsLoading(false);
    return false;
  };

  // ========== 학습 보고서 데이터 교환 기능 ==========
  
  // 현재 학생의 학습 보고서 내보내기
  // 학생 이관용 내보내기
  const exportStudentReport = (isTransfer = false) => {
    if (!reportData.studentName || !reportData.studentName.trim()) {
      alert('먼저 학생을 선택하거나 이름을 입력해주세요.');
      return;
    }
    
    try {
      const currentTeacher = reportData.teacher || loggedInTeacher?.name || '선생님';
      
      const exportData = {
        _exportInfo: {
          type: 'paran_math_student_report',
          version: '1.0',
          exportedAt: new Date().toISOString(),
          studentName: reportData.studentName,
          exportedBy: currentTeacher,
          isTransfer: isTransfer, // 이관용 여부
          previousTeacher: isTransfer ? currentTeacher : null // 이전 담당 선생님
        },
        reportData: {
          ...reportData,
          // 이관 시 이전 담당 선생님 기록
          transferHistory: [
            ...(reportData.transferHistory || []),
            ...(isTransfer ? [{
              date: new Date().toISOString(),
              from: currentTeacher,
              to: '(이관 대기)',
              exportedAt: new Date().toISOString()
            }] : [])
          ]
        }
      };
      
      const dataStr = JSON.stringify(exportData, null, 2);
      const blob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      
      const a = document.createElement('a');
      a.href = url;
      const prefix = isTransfer ? '학생이관' : '학습보고서';
      a.download = `${prefix}_${reportData.studentName}_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      
      if (isTransfer) {
        alert(`✅ ${reportData.studentName} 학생의 이관 파일을 생성했습니다.\n\n이 파일을 새 담당 선생님에게 전달하세요.\n새 선생님이 '가져오기'하면 담당이 변경됩니다.`);
      } else {
        alert(`✅ ${reportData.studentName} 학생의 학습 보고서를 내보냈습니다.\n\n다른 선생님에게 이 파일을 공유하세요.`);
      }
    } catch (error) {
      console.error('내보내기 실패:', error);
      alert('❌ 내보내기에 실패했습니다.');
    }
  };
  
  // 학습 보고서 파일 선택 처리
  const handleImportFileSelect = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    
    if (!file.name.endsWith('.json')) {
      alert('JSON 파일만 가져올 수 있습니다.');
      return;
    }
    
    setImportFile(file);
    setImportStatus('reading');
    
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target.result);
        
        // 파일 유효성 검사
        if (!data._exportInfo || data._exportInfo.type !== 'paran_math_student_report') {
          alert('❌ 올바른 학습 보고서 파일이 아닙니다.');
          setImportFile(null);
          setImportPreview(null);
          setImportStatus('');
          return;
        }
        
        if (!data.reportData) {
          alert('❌ 보고서 데이터가 없습니다.');
          setImportFile(null);
          setImportPreview(null);
          setImportStatus('');
          return;
        }
        
        setImportPreview(data);
        setImportStatus('ready');
      } catch (error) {
        console.error('파일 파싱 오류:', error);
        alert('❌ 파일을 읽을 수 없습니다.');
        setImportFile(null);
        setImportPreview(null);
        setImportStatus('');
      }
    };
    reader.readAsText(file);
  };
  
  // 학습 보고서 가져오기 실행
  const executeImport = async (mode) => {
    if (!importPreview || !importPreview.reportData) {
      alert('가져올 데이터가 없습니다.');
      return;
    }
    
    // 이관 모드인데 새 담당 선생님이 없으면
    if (mode === 'transfer' && !importNewTeacher.trim()) {
      alert('새 담당 선생님 이름을 입력해주세요.');
      return;
    }
    
    setImportStatus('importing');
    
    try {
      let importedData = { ...importPreview.reportData };
      const studentName = importedData.studentName;
      const exportInfo = importPreview._exportInfo || {};
      
      // 이관 모드: 담당 선생님 변경 + 이력 기록
      if (mode === 'transfer') {
        const previousTeacher = exportInfo.previousTeacher || importedData.teacher || '이전 담당';
        const newTeacher = importNewTeacher.trim();
        
        // 이관 이력 완성
        const transferHistory = importedData.transferHistory || [];
        const lastTransfer = transferHistory[transferHistory.length - 1];
        
        if (lastTransfer && lastTransfer.to === '(이관 대기)') {
          // 기존 이관 대기 항목 완성
          lastTransfer.to = newTeacher;
          lastTransfer.completedAt = new Date().toISOString();
        } else {
          // 새 이관 이력 추가
          transferHistory.push({
            date: new Date().toISOString(),
            from: previousTeacher,
            to: newTeacher,
            completedAt: new Date().toISOString()
          });
        }
        
        importedData = {
          ...importedData,
          teacher: newTeacher,
          previousTeacher: previousTeacher,
          transferHistory: transferHistory,
          transferredAt: new Date().toISOString()
        };
        
        // 데이터 저장
        setReportData(importedData);
        
        if (typeof window !== 'undefined' && window.storage && typeof window.storage.set === 'function') {
          await window.storage.set(reportKey(studentName), JSON.stringify(importedData));
          // already handled
        }
        localStorage.setItem(reportKey(studentName), JSON.stringify(importedData));
        localStorage.setItem(reportKey(studentName), JSON.stringify(importedData));
        
        alert(`✅ ${studentName} 학생이 ${newTeacher} 선생님에게 이관되었습니다.\n\n• 이전 담당: ${previousTeacher}\n• 새 담당: ${newTeacher}\n• 수업 기록: ${importedData.sessions?.length || 0}회 전체 이관`);
        
      } else if (mode === 'replace') {
        // 기존 데이터 완전 교체
        setReportData(importedData);
        
        // 클라우드에도 저장
        if (typeof window !== 'undefined' && window.storage && typeof window.storage.set === 'function') {
          await window.storage.set(reportKey(studentName), JSON.stringify(importedData));
          // already handled
        }
        localStorage.setItem(reportKey(studentName), JSON.stringify(importedData));
        localStorage.setItem(reportKey(studentName), JSON.stringify(importedData));
        
        alert(`✅ ${studentName} 학생의 학습 보고서를 가져왔습니다.`);
        
      } else if (mode === 'merge') {
        // 기존 데이터와 병합 (세션 추가)
        const existingData = { ...reportData };
        const existingSessions = existingData.sessions || [];
        const importedSessions = importedData.sessions || [];
        
        // 중복 방지: 날짜+회차가 같은 세션은 제외
        const existingKeys = existingSessions.map(s => `${s.date}_${s.sessionNumber}`);
        const newSessions = importedSessions.filter(s => 
          !existingKeys.includes(`${s.date}_${s.sessionNumber}`)
        );
        
        const mergedData = {
          ...existingData,
          sessions: [...existingSessions, ...newSessions].sort((a, b) => 
            a.date.localeCompare(b.date) || (a.sessionNumber || 0) - (b.sessionNumber || 0)
          )
        };
        
        setReportData(mergedData);
        
        // 클라우드에도 저장
        if (typeof window !== 'undefined' && window.storage && typeof window.storage.set === 'function') {
          await window.storage.set(reportKey(studentName), JSON.stringify(mergedData));
          await window.storage.set(reportKey(studentName), JSON.stringify(mergedData));
        }
        localStorage.setItem(reportKey(studentName), JSON.stringify(mergedData));
        localStorage.setItem(reportKey(studentName), JSON.stringify(mergedData));
        
        alert(`✅ ${newSessions.length}개의 수업 기록이 추가되었습니다.`);
      }
      
      // 학생 목록 갱신
      if (!savedStudents.includes(studentName)) {
        setSavedStudents(prev => [...prev, studentName]);
      }
      
      setImportStatus('done');
      setShowDataExchangeModal(false);
      setImportFile(null);
      setImportPreview(null);
      setImportNewTeacher('');
      setSaveStatus('saved');
      
    } catch (error) {
      console.error('가져오기 실패:', error);
      alert('❌ 가져오기에 실패했습니다.');
      setImportStatus('error');
    }
  };
  
  // 여러 학생 일괄 내보내기
  const exportMultipleStudents = async () => {
    if (savedStudents.length === 0) {
      alert('저장된 학생이 없습니다.');
      return;
    }
    
    try {
      const allReports = {};
      
      for (const studentName of savedStudents) {
        const result = await window.storage.get(reportKey(studentName));
        if (result && result.value) {
          allReports[studentName] = JSON.parse(result.value);
        }
      }
      
      const exportData = {
        _exportInfo: {
          type: 'paran_math_bulk_reports',
          version: '1.0',
          exportedAt: new Date().toISOString(),
          studentCount: Object.keys(allReports).length,
          students: Object.keys(allReports)
        },
        reports: allReports
      };
      
      const dataStr = JSON.stringify(exportData, null, 2);
      const blob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      
      const a = document.createElement('a');
      a.href = url;
      a.download = `학습보고서_전체_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      
      alert(`✅ ${Object.keys(allReports).length}명의 학습 보고서를 내보냈습니다.`);
    } catch (error) {
      console.error('일괄 내보내기 실패:', error);
      alert('❌ 내보내기에 실패했습니다.');
    }
  };
  
  // 여러 학생 일괄 가져오기
  const handleBulkImportFileSelect = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const data = JSON.parse(event.target.result);
        
        if (data._exportInfo?.type === 'paran_math_bulk_reports' && data.reports) {
          // 일괄 가져오기
          const reports = data.reports;
          const studentNames = Object.keys(reports);
          
          if (!confirm(`${studentNames.length}명의 학습 보고서를 가져오시겠습니까?\n\n학생: ${studentNames.join(', ')}`)) {
            return;
          }
          
          let successCount = 0;
          for (const [studentName, reportData] of Object.entries(reports)) {
            try {
              if (typeof window !== 'undefined' && window.storage && typeof window.storage.set === 'function') {
                await window.storage.set(reportKey(studentName), JSON.stringify(reportData));
              }
              localStorage.setItem(reportKey(studentName), JSON.stringify(reportData));
              successCount++;
            } catch (err) {
              console.error(`${studentName} 저장 실패:`, err);
            }
          }
          
          await loadStudentList();
          alert(`✅ ${successCount}명의 학습 보고서를 가져왔습니다.`);
          setShowDataExchangeModal(false);
          
        } else if (data._exportInfo?.type === 'paran_math_student_report') {
          // 개별 학생 - 미리보기 모드로 전환
          setImportPreview(data);
          setImportStatus('ready');
        } else {
          alert('❌ 올바른 학습 보고서 파일이 아닙니다.');
        }
      } catch (error) {
        console.error('파일 파싱 오류:', error);
        alert('❌ 파일을 읽을 수 없습니다.');
      }
    };
    reader.readAsText(file);
  };

  // 오답 데이터 파싱 함수
  const parseWrongProblems = (wrongProblemsText, textbook, customTextbook, sessionDate) => {
    if (!wrongProblemsText || typeof wrongProblemsText !== 'string') return [];
    
    const notes = [];
    const tb = textbook === '기타' ? (customTextbook || '기타') : textbook;
    
    // 패턴 1: "p.25 3번, p.26 5,7번" 형식
    const pagePattern = /p\.?(\d+)[-~]?(\d+)?\s*[:-]?\s*([\d,\s번]+)?/gi;
    let match;
    
    while ((match = pagePattern.exec(wrongProblemsText)) !== null) {
      const page = match[1];
      const problemNumbers = match[3] ? match[3].replace(/번/g, '').split(/[,\s]+/).filter(n => n.trim()) : [];
      
      if (problemNumbers.length > 0) {
        problemNumbers.forEach(num => {
          if (num.trim()) {
            notes.push({
              id: `auto_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
              textbook: textbook,
              customTextbook: customTextbook || '',
              page: page,
              problemNumber: num.trim(),
              wrongAnswer: '',
              correctAnswer: '',
              unit: '',
              type: '',
              explanation: '',
              conquered: false,
              createdAt: new Date().toISOString(),
              sessionDate: sessionDate,
              autoImported: true
            });
          }
        });
      }
    }
    
    return notes;
  };

  // 시험 오답 추출 함수 (레거시 + 다중 시험 지원)
  const extractTestWrongAnswers = (session) => {
    const results = [];
    
    // 레거시 시험 (testAnswers)
    if (session.testAnswers && session.testAnswers.length > 0) {
      const wrongIndices = session.testAnswers
        .map((answer, idx) => answer === false ? idx + 1 : null)
        .filter(n => n !== null);
      
      if (wrongIndices.length > 0) {
        const testName = session.testType === '기타' ? (session.customTestName || '기타 시험') : session.testType;
        wrongIndices.forEach(num => {
          results.push({
            id: `test_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            textbook: '시험',
            customTextbook: testName,
            page: session.testScope || '',
            problemNumber: String(num),
            wrongAnswer: '',
            correctAnswer: '',
            unit: '',
            type: '',
            explanation: '',
            conquered: false,
            createdAt: new Date().toISOString(),
            sessionDate: session.date,
            autoImported: true,
            difficulty: session.difficulty || 'medium'
          });
        });
      }
    }
    
    // 다중 시험 (tests 배열)
    if (session.tests && session.tests.length > 0) {
      session.tests.forEach(test => {
        if (test.testAnswers && test.testAnswers.length > 0) {
          const wrongIndices = test.testAnswers
            .map((answer, idx) => answer === false ? idx + 1 : null)
            .filter(n => n !== null);
          
          if (wrongIndices.length > 0) {
            const testName = test.testType === '기타' ? (test.customTestName || '기타 시험') : test.testType;
            wrongIndices.forEach(num => {
              results.push({
                id: `test_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
                textbook: '시험',
                customTextbook: testName,
                page: test.testScope || '',
                problemNumber: String(num),
                wrongAnswer: '',
                correctAnswer: '',
                unit: '',
                type: '',
                explanation: '',
                conquered: false,
                createdAt: new Date().toISOString(),
                sessionDate: session.date,
                autoImported: true,
                difficulty: test.difficulty || 'medium'
              });
            });
          }
        }
      });
    }
    
    return results;
  };

  // 오답 문제 은행용 데이터 변환 함수
  const convertToWrongBankFormat = (wrongNote, studentId) => {
    return {
      id: Date.now() + Math.floor(Math.random() * 10000),
      studentId: studentId,
      textbook: wrongNote.textbook || '',
      customTextbook: wrongNote.customTextbook || '',
      page: wrongNote.page || '',
      problemNumber: wrongNote.problemNumber || '',
      unit: wrongNote.unit || '',
      wrongType: wrongNote.type || '',
      difficulty: wrongNote.difficulty || 'medium',
      memo: wrongNote.textbook === '시험' 
        ? `${wrongNote.customTextbook} - ${wrongNote.problemNumber}번 문제`
        : `${wrongNote.textbook === '기타' ? wrongNote.customTextbook : wrongNote.textbook} p.${wrongNote.page} ${wrongNote.problemNumber}번`,
      date: wrongNote.sessionDate || new Date().toISOString().split('T')[0],
      reviewStatus: 'pending',
      reviewHistory: [],
      createdAt: new Date().toISOString(),
      nextReviewDate: new Date().toISOString().split('T')[0],
      fromReport: true
    };
  };

  const saveStudentData = async () => {
    if (!reportData.studentName || reportData.studentName.trim() === '') return;
    setSaveStatus('saving');
    try {
      const dataToSave = JSON.stringify(reportData);
      await window.storage.set(reportKey(reportData.studentName.trim()), dataToSave);
      
      // 오답노트 및 오답 문제 은행 자동 연동
      if (students && saveStudents) {
        const studentName = reportData.studentName.trim();
        const student = students.find(s => s.name === studentName);
        
        if (student) {
          let newWrongNotes = [];
          const existingNotes = student.wrongNotes || [];
          
          // 현재 세션에서 오답 추출
          const currentSession = reportData.sessions[reportData.currentSessionIndex];
          if (currentSession) {
            // 문제풀이 오답
            (currentSession.problemSets || []).forEach(ps => {
              if (ps.wrongProblems) {
                const parsed = parseWrongProblems(ps.wrongProblems, ps.textbook, ps.customTextbook, currentSession.date);
                newWrongNotes = [...newWrongNotes, ...parsed];
              }
            });
            
            // 과제 오답
            (currentSession.assignments || []).forEach(assignment => {
              if (assignment.wrongProblems) {
                const parsed = parseWrongProblems(assignment.wrongProblems, assignment.textbook, assignment.customTextbook, currentSession.date);
                newWrongNotes = [...newWrongNotes, ...parsed];
              }
            });
            
            // 시험 오답 (레거시 + 다중 시험)
            const testWrongs = extractTestWrongAnswers(currentSession);
            newWrongNotes = [...newWrongNotes, ...testWrongs];
          }
          
          // 중복 제거 (같은 교재+페이지+문제번호+날짜)
          const uniqueNewNotes = newWrongNotes.filter(newNote => {
            return !existingNotes.some(existing => 
              existing.textbook === newNote.textbook &&
              existing.page === newNote.page &&
              existing.problemNumber === newNote.problemNumber &&
              existing.sessionDate === newNote.sessionDate
            );
          });
          
          // 오답노트에 추가
          if (uniqueNewNotes.length > 0) {
            const updatedStudents = students.map(s => {
              if (s.id === student.id) {
                return { ...s, wrongNotes: [...existingNotes, ...uniqueNewNotes] };
              }
              return s;
            });
            saveStudents(updatedStudents);
            console.log(`오답노트 ${uniqueNewNotes.length}개 자동 추가됨`);
          }
          
          // 오답 문제 은행에도 추가
          if (uniqueNewNotes.length > 0) {
            try {
              let existingProblems = [];
              try {
                const result = await window.storage.get(wrongProblemsKey());
                if (result && result.value) existingProblems = JSON.parse(result.value);
              } catch (e) { console.log('기존 오답 로드:', e); }
              
              // 오답 문제 은행 형식으로 변환
              const newBankProblems = uniqueNewNotes.map(note => convertToWrongBankFormat(note, student.id));
              
              // 중복 제거
              const uniqueBankProblems = newBankProblems.filter(np => 
                !existingProblems.some(ep => 
                  ep.studentId === np.studentId &&
                  ep.date === np.date &&
                  ep.problemNumber === np.problemNumber &&
                  ep.textbook === np.textbook &&
                  (ep.page === np.page || (!ep.page && !np.page))
                )
              );
              
              if (uniqueBankProblems.length > 0) {
                await window.storage.set(wrongProblemsKey(), JSON.stringify([...existingProblems, ...uniqueBankProblems]));
                console.log(`오답 문제 은행 ${uniqueBankProblems.length}개 자동 추가됨`);
              }
            } catch (e) {
              console.error('오답 문제 은행 저장 오류:', e);
            }
          }
        }
      }
      
      setSaveStatus('saved');
      if (!savedStudents.includes(reportData.studentName.trim())) {
        setSavedStudents(prev => [...prev, reportData.studentName.trim()]);
      }

      // ─── 기능1: 수업 완료 시 학부모 실시간 알림 자동 생성 ───
      try {
        const currentSession = reportData.sessions[reportData.currentSessionIndex];
        if (currentSession) {
          const studentName = reportData.studentName.trim();
          const totalProblems = (currentSession.problemSets || []).reduce((s, ps) => s + (Number(ps.totalProblems) || 0), 0);
          const totalCorrect = (currentSession.problemSets || []).reduce((s, ps) => s + (Number(ps.correctAnswers) || 0), 0);
          const accuracy = totalProblems > 0 ? Math.round((totalCorrect / totalProblems) * 100) : null;
          const units = (currentSession.lessonContents || []).map(lc => lc.subUnit || lc.mainUnit).filter(Boolean);
          const assignments = (currentSession.assignments || []).filter(a => a.pages).map(a => `${a.textbook ? a.textbook + ' ' : ''}p.${a.pages}`);
          const praise = currentSession.praiseMessage || '';
          const notification = {
            id: Date.now(),
            type: 'lesson_complete',
            studentName,
            date: currentSession.date || new Date().toISOString().split('T')[0],
            time: new Date().toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' }),
            unit: units.length > 0 ? units.join(', ') : (currentSession.note || ''),
            accuracy,
            totalProblems,
            totalCorrect,
            assignments: assignments.join(', '),
            praise,
            understanding: currentSession.understanding,
            read: false,
            createdAt: new Date().toISOString()
          };
          const notifKey = slugKey(`paran:lesson_notifications:${studentName}`);
          let existingNotifs = [];
          try {
            const stored = localStorage.getItem(notifKey);
            if (stored) existingNotifs = JSON.parse(stored);
          } catch (e) {}
          const updated = [notification, ...existingNotifs].slice(0, 50);
          localStorage.setItem(notifKey, JSON.stringify(updated));
          if (window.storage) window.storage.set(notifKey, JSON.stringify(updated)).catch(() => {});
          window.dispatchEvent(new CustomEvent('lessonNotification', { detail: { studentName, notification } }));
        }
      } catch (notifErr) { console.log('알림 생성 오류:', notifErr); }

      setTimeout(() => setSaveStatus(''), 2000);
    } catch (error) {
      console.error('저장 실패:', error);
      setSaveStatus('error');
      setTimeout(() => setSaveStatus(''), 3000);
    }
  };

  const confirmDelete = async () => {
    if (!deleteConfirm) return;
    const studentName = deleteConfirm;
    try {
      await window.storage.delete(reportKey(studentName));
    } catch (error) {
      console.log('스토리지 삭제:', error);
    }
    setSavedStudents(prev => prev.filter(name => name !== studentName));
    if (reportData.studentName === studentName) {
      setReportData({
        studentName: '', grade: '', className: '', teacher: '',
        reportDate: new Date().toISOString().split('T')[0], reportPeriod: '',
        sessions: [], currentSessionIndex: -1, goalAccuracy: 80, goalDescription: '',
        upcomingTests: [{ testType: '', testDate: '', testScope: '', customTestName: '', difficulty: '', actualAccuracyMin: '', actualAccuracyMax: '' }],
        additionalStrengths: [''], additionalImprovements: [''],
        teacherComment: '', homeStudyGuide: '', nextClassPrep: ['']
      });
    }
    setDeleteConfirm(null);
  };

